SELECT * FROM store WHERE dutyAddr LIKE CONCAT('%', #{dutyAddr1}, '%') AND dutyAddr LIKE CONCAT('%', #{dutyAddr2}, '%')
AND dutyName LIKE CONCAT('%', #{dutyName}, '%')
ORDER BY dutyName limit #{recordSize} offset #{offset}

select s.*, p.*
from store_stock s join product p
where s.product_id = p.id and s.store_id = #{storeId};
